var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"으아아악! ……야!","JPN":"わあああっ！　……おい！","ENG":"Eww! …Hey!","TWN":"呃啊啊啊！ …喂！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"부르셨습니까, 주인님?","JPN":"お呼びでしょうか、ご主人様?","ENG":"Did you call, Mistress?","TWN":"主人叫我嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"더는 못 참겠다! 집안에 날리는 이 털들은 다 뭐야!","JPN":"もう勘弁できん！　家中に漂っているこの毛はいったいなんじゃ！","ENG":"I can’t take it anymore! Just look at all the fur flying around in the house!","TWN":"我受不了了！家裡到處飛的這些毛到底是怎麼回事！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저런, 보름달이 가까워지고 있기에 유마를 외출하지 못하도록 붙잡아뒀습니다만.","JPN":"おっと、満月が近いのでユマを外出禁止にしておきましたが。","ENG":"Oh my... Since the full moon is about to appear, I've had Yuma grounded.","TWN":"哎呀，因為月圓快到了，我才把游馬關在家裡，不讓她外出。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"마침 초겨울이라서 털갈이 시기가 맞물렸나 보네요.","JPN":"ちょうど初冬ですので、換毛期と重なったようです。","ENG":"But with winter approaching, she must be in the process of shedding.","TWN":"剛好現在是冬季，是換毛的時期。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"아, 몰라! 몰라! 지금 당장 밖으로 내보내! 이 망할 털 때문에 숨을 못 쉬겠다고!","JPN":"もう知らん！　知らんぞ！　今すぐ外に出せ！　このクソ毛のせいで息ができぬではないか！","ENG":"Ugh! I've had about enough! Take her outside! With all the fur flying around, I can't breathe!","TWN":"我不管啦！現在馬上把她趕出去！這該死的毛害我都無法好好呼吸！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"주인님? 이렇게 달이 밝은 밤에 유마를 혼자 돌아다니게 하는 건 위험합니다.","JPN":"ご主人様？　こうして月が明るい夜に、ユマを一人で歩かせることは危険です。","ENG":"Mistress? With the moon shining bright tonight, letting Yuma out alone is far too dangerous.","TWN":"主人？在這樣月光明亮的夜晚，讓游馬一個人在外面是很危險的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"인간들의 입을 타고 소문이라도 퍼진다면 저희 입장까지 곤란해질 테니까요.","JPN":"人間たちの間で噂が広まれば、私たちまで困りますので。","ENG":"If word gets out to the humans, it will do no good for us.","TWN":"如果傳到人類的耳朵裡，甚至傳出謠言的話，我們的處境也會變得很為難。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그까짓 건 내 상관할 바가 아니지.","JPN":"そんなもの、妾が気にする必要などあるまい。","ENG":"That’s not my problem, is it?","TWN":"那不關我的事。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"내가 인간들 눈치 보느라 개털을 들이마셔야겠어?","JPN":"妾が人間の目が怖くて犬の毛を吸い込まないといけないということか？","ENG":"Why do I have to suffer and breathe in fur because of some humans?","TWN":"我難道會因為懼怕人類就繼續吸這些狗毛嗎？！"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"밖에 내보내고 네가 따라다니던지 하라고.","JPN":"外に出して、お前がついて行け。","ENG":"Take her outside and you stay right beside her.","TWN":"把她趕出去，你也跟著她一起。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"…알겠습니다.","JPN":"……わかりました。","ENG":"...Yes, ma'am.","TWN":"…我知道了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"여차했을 땐, 제가 목격자를 모두 처리하도록 하죠.","JPN":"いざと言う時には、私が目撃者を全部処理するとしましょう。","ENG":"If we get any witnesses, I’ll make sure they don’t speak a word.","TWN":"萬一發生什麼事，我會處理掉所有目擊者。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"으, 머리 아파.","JPN":"うう、頭痛い。","ENG":"Ugh... My head...","TWN":"唉，真是頭疼。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"뭐라도 짓밟아버리면 좀 개운해지려나.","JPN":"何か踏みにじると、ちょっとすっきりするかな。","ENG":"It would really clear my head if I could just pummel something.","TWN":"心情真差，真想找個對象出出氣。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"아, 어깨 나갈 뻔했네. 이거 어떻게 책임질 거요?","JPN":"あ、肩折れるところだったじゃねえか。どうやって責任取ってくれるんだ？","ENG":"Hey, you! You almost dislocated my shoulder!","TWN":"啊，肩膀差點脫臼了。你要怎麼負責？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"뭐야, 넌?","JPN":"なんだ、あんたは。","ENG":"What do you want?","TWN":"嗯？你是誰？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"이야, 눈빛으로 사람을 아주 잡아먹겠구만.","JPN":"おいおい、目線で人でも殺しそうじゃねえか。","ENG":"What are you staring at, huh?","TWN":"哎呀，看你的眼神，是要吃人啊。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"너, 요즘 이 골목에서 닥치는 대로 사람 묵사발을 내고 다닌다지?","JPN":"お前、最近この路地で手あたり次第に人を殴りまくってるらしいな。","ENG":"So you’re the one that goes around beating people up, eh?","TWN":"你，最近在這條巷子裡見人就揍，是吧？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"우리 부하들만 건드리지 않았다면 적당히 넘어가려고 했는데, 어젠 우리 애들이 꽤 신세를 많이 졌더군.","JPN":"俺の部下に手を出さなけりゃ適当に見逃すつもりだったんだが、昨日はうちの子たちが偉くお世話になってよぉ。","ENG":"I was gonna turn a blind eye if you left my men alone, but after what you did to them yesterday...","TWN":"要是你沒動到我的手下，我還可以睜隻眼閉隻眼，但昨天我的弟兄們可受了不少罪。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"주먹으로 실수를 했으면, 주먹으로 갚아야지. 안 그래?","JPN":"拳で過ちを犯したんなら、拳で返すべきだろな。違うか？","ENG":"An eye for an eye, a punch for a punch, right?","TWN":"用拳頭欠的債，就要用拳頭償還。不是嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어, 그래.","JPN":"あ、そう。","ENG":"Sure, whatever.","TWN":"對，正合我意。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"우와아악!","JPN":"うわあああ！","ENG":"Gaaaah!","TWN":"哇啊啊啊！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_C","text":{"KOREA":"혀, 형님!","JPN":"あ、兄貴！","ENG":"B-boss!","TWN":"大，大哥！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"뭐해? 빨리 주먹 빚 갚아야지?","JPN":"何をしている？　早く拳で返してみろよ。","ENG":"What? No punch back?","TWN":"怎樣？不是說要還債嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"……뭐, 뭐야. 뭐 이런 엄청난 괴력이 다 있어?","JPN":"……な、なんだ？　なんて怪力なんだよ？","ENG":"...W-what the hell?! Y-you’re a monster!","TWN":"…什，什麼啊。怎麼會有如此驚人的怪力？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"덤빌 거면 빨리 덤벼. 마침 피가 보고 싶었거든.","JPN":"かかってくるなら早くかかってこい。ちょうど血が見たかったんだ。","ENG":"Come at me if you want. I’ve been itching for a fight anyway.","TWN":"要打就快點過來吧，正好我也想見見血了。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"우, 우왓, 오, 오지마!","JPN":"う、うわあっ！　く、来るな！","ENG":"W-whoa! S-stay back!","TWN":"哇，哇，不，不要過來！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"니들, 뭘 보고만 있어! 총은 장식이냐! 쏴! 쏴버리라고!","JPN":"てめえら、何してんだ！　銃あるだろ！？　撃て！　撃っちゃえ！","ENG":"What are you standing around for, huh?! Shoot her!","TWN":"你們，還愣著幹什麼！槍是拿來看的嗎！還不開槍！快開槍啊！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_C","text":{"KOREA":"네? ……네!","JPN":"へ？　……はい！","ENG":"H-huh? ...Yes, boss!","TWN":"啊？…好的！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"큿!","JPN":"くっ！","ENG":"Ack!","TWN":"呃！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"……따갑잖아! 이 자식아!","JPN":"……チクチクするだろうが！　この野郎！","ENG":"...Hey! That hurt, you jerk!","TWN":"…好痛啊！你這傢伙！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_C","text":{"KOREA":"흐아아악!","JPN":"うわあああっ！","ENG":"Aaargh!","TWN":"呃啊啊啊！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"이런 미친. 카운터라고?","JPN":"そんなバカな。カウンターだと？","ENG":"What the... S-she’s a Counter?!","TWN":"這瘋女人，難道是制裁者？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"더 쏴! 아주 벌집을 내버려!","JPN":"もっと撃て！　ハチの巣にしちゃえ！","ENG":"Shoot her! Turn her into Swiss cheese!!","TWN":"繼續開槍！把她射成蜂窩！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"하아…… 하…….","JPN":"はあ……はあ……","ENG":"Huff... Huff...","TWN":"呼…呼…"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_C","text":{"KOREA":"괴, 괴물이다.","JPN":"ば、化け物だ。","ENG":"M-monster.","TWN":"怪，怪物。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_03"},{"id":"L32_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_C","text":{"KOREA":"……저건 괴물이야!","JPN":"……あれは化け物なんだ！","ENG":"...She’s a monster!","TWN":"…絕對是個怪物！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"크큭……. 크하하하.","JPN":"ククッ……はははは。","ENG":"Keke... Bwahaha!","TWN":"哈…哈哈哈。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"야.","JPN":"おい。","ENG":"Hey.","TWN":"喂。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그렇게 겁에 질린 사슴처럼 소릴 지르면, 내가 더 참을성이 없어지잖아.","JPN":"そうやって怖気づいた鹿のように叫ぶと、アタシがもっと我慢できなくなるだろう。","ENG":"Your screaming like a frightened deer is just testing my patience to the limit.","TWN":"你要是像受驚的鹿一樣尖叫，會讓我更沒有耐心的。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_C","text":{"KOREA":"저 여자, 눈이…… 왜 저래? 카운터의 능력 같은 건가?","JPN":"あの女、目が……どうしたんだ？　カウンター能力みたいなものか？","ENG":"Look at her eyes…! Is it her Counter ability?","TWN":"那個女人的眼睛…怎麼回事？是制裁者的能力嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_15"},{"id":"L42_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"아니야… 저런 건 들어본 적도 없다고.","JPN":"違えよ……あんなことは聞いたこともねえ。","ENG":"No... I’ve never seen anything like it before.","TWN":"不可能…我從來沒聽說過那種事。"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YUMA_WOLF_NAME_YUMA","text":{"KOREA":"크아아아아아!!!!","JPN":"グアアアアア！！！！","ENG":"Groarr!!","TWN":"咳啊啊啊啊啊！！！"},"stage":{"bg":"BACKSTREET2","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_WOLF_NAME_YUMA","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_28"},{"id":"L47_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L48_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"목에 이건 또 뭐야? 다트?","JPN":"首になんか刺さったぞ？　ダーツ？","ENG":"What’s this? A dart?","TWN":"脖子上的這又是什麼？飛鏢？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"…이런, 마취총 정도로는 역시 통하지 않는 건가?","JPN":"……しまった。麻酔銃くらいではやはり通じないのか？","ENG":"…Tsk, the tranq gun’s no use on her.","TWN":"…嘖，麻醉槍也沒用嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_POLICE_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"어이, 이거 네가 쏜 거냐?","JPN":"おい、これあんたが撃ったのか？","ENG":"Hey, did you do this?","TWN":"喂，這是你射的嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"아, 아니야! 내가 그런 게 아니라고!","JPN":"ち、違う！　俺じゃねんだ！","ENG":"N-no! It wasn’t me!","TWN":"不，不是的！不是我射的！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"크하하, 뭔진 모르겠지만 기분 째지는데!","JPN":"あはは、なんだかよくわからないけど気持ちいいな！","ENG":"Kwahaha! I don’t know what you did, but it feels great!","TWN":"哈哈哈，雖然不知道是什麼，但感覺真爽啊！"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"그럼 이 기세로 전부 박살을 내볼까?","JPN":"じゃあ、この勢いで全部壊してみるか？","ENG":"Now then... How should I smash every single one of you?","TWN":"那就趁著這股氣勢把一切都打爆吧？"},"stage":{"bg":"BACKSTREET2","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"음? 마취총이… 통했나?","JPN":"む？　麻酔銃が……通じたのか？","ENG":"Huh? Did the tranquilizer work...?","TWN":"嗯？麻醉槍…起作用了嗎？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"히이익……! 죽일 듯이 굴더니 갑자기 왜 저래?","JPN":"ひいいっ……！　殺す気でかかってくるかと思ったら、いきなりなんだ？","ENG":"Whoa...! I thought I was a goner!","TWN":"欸欸欸…！剛才還一副要殺人的樣子，現在怎麼突然這樣？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"뭐, 뭐야? 왜 쓰러졌지?","JPN":"な、何だ？　なんで倒れたんだよ？","ENG":"Huh? But why’d she suddenly faint?","TWN":"怎，怎麼了？為什麼倒下了？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"이런, 저희 친구가 과음을 해버려서 여러분에게 폐를 끼친 모양이네요.","JPN":"やれやれ、私の友だちが飲みすぎてみなさんに迷惑をかけたようですね。","ENG":"Oh, guess my friend here had too much to drink.","TWN":"哎呀，我的朋友喝多了，不好意思給大家添麻煩了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_POLICE_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"……드르렁-","JPN":"……ぐうー","ENG":"...Groarghhhrr...","TWN":"…呼嚕—"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_POLICE_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"이거, 실례했습니다.","JPN":"これは、失礼。","ENG":"Sorry for your troubles.","TWN":"先告辭囉。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PERSON_EXTRA_POLICE_MINWOO","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_BIG","text":{"KOREA":"사…… 살았다.","JPN":"た……助かった。","ENG":"Whew... Thank god.","TWN":"…得救了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_C","text":{"KOREA":"방금, 몸을 움직일 수가 없었어.","JPN":"今、身動きが取れなかったぞ。","ENG":"It was like I was paralyzed.","TWN":"剛才，身體動不了。"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_B","text":{"KOREA":"대체…… 저게 뭐야?","JPN":"あれ……いったい何なんだ？","ENG":"What the hell was that thing...?","TWN":"那究竟…是什麼？"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CRIMINAL_NPC_MEMBER_B","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"코끼리도 기절시킬 정도의 마취약이라 과잉진압은 아닐지 걱정했는데…","JPN":"ゾウも気絶させるほどの麻酔薬で、やり過ぎではないかと心配したんだが……","ENG":"I was worried I went too far using a sedative made for elephants...","TWN":"這可是能讓大象都昏倒的麻醉藥，我還擔心會不會過量了…"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"맞고도 한참 뒤에야 반응이 올 정도라니, 보통 카운터는 아니군.","JPN":"撃たれてもしばらくして反応が来るくらいとは、普通のカウンターではないな。","ENG":"But, given that it didn't take effect right away, I guess she's not the average Counter.","TWN":"這麼久才有反應，看來不是普通的制裁者。"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"그런데 그 순간에 보였던 그 눈빛은……","JPN":"ところで、あの瞬間見えたあの目は……","ENG":"But her eyes...","TWN":"但是那一瞬間眼中的光芒…"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"……대체 뭐였지?","JPN":"……いったい何だったんだ？","ENG":"I mean, what was that?","TWN":"…到底是什麼？"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"눈빛으로 사람을 얼어붙게 하는 카운터 얘긴 들어본 적도 없는데……","JPN":"目線で人を凍らせるようなカウンターの話など聞いたこともないが……","ENG":"I've never heard of a Counter freezing people simply by staring at them...","TWN":"從沒聽說過有制裁者能用眼神把人震懾住…"},"stage":{"bg":"BACKSTREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"으음……","JPN":"うーん……","ENG":"Mm...","TWN":"嗯…"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"이런, 제 동생이 길가에 쓰러져있는 걸 발견해서 데려오셨다고요.","JPN":"おっと、私の妹が道に倒れていたところを見つけて連れて来てくださったのですか？","ENG":"Oh dear, you brought my sister back after finding her passed out on the streets?","TWN":"天啊，你說發現我妹妹倒在路邊，然後把她帶過來了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저희가 신세를 졌네요, 순경님.","JPN":"本当にお世話になりました、巡査。","ENG":"Thank you for your help, officer.","TWN":"我們欠你一個人情，警察先生。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"사실 목덜미 쪽에 타박상이 있는 듯 해서 병원으로 옮기려 했습니다만, 금세 회복을 하시더군요.","JPN":"実は首筋の方に打撲傷があるようで病院に運ぼうと思っていたのですが、すぐ回復したんです。","ENG":"I saw she had a bruise on her neck, so I was about to take her to the hospital. But she's already recovered.","TWN":"其實我看到脖子似乎有瘀青，本來打算送去醫院，但她很快就恢復了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"역시 카운터는 달라도 뭔가 다르더라고요.","JPN":"やはりカウンターは違いますね。","ENG":"Counters are truly impressive.","TWN":"果然制裁者就是不一樣啊。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"말씀대로입니다. 제 동생이 조금…… 특별하긴 하죠.","JPN":"おっしゃる通りです。私の妹が少々……特別ではあります。","ENG":"Yes... My little sister is... ”special\\" to say the least.","TWN":"你說的對，我妹妹確實有點…特別。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그건 그렇고, 마침 고급 차가 준비됐는데. 한 잔 드시고 가겠습니까?","JPN":"それはそうと、ちょうど高級なお茶を淹れたのですが。一杯どうですか？","ENG":"Officer? I’ve made myself some fine tea. Would you like to have a cup?","TWN":"話說回來，我正好沏了壺上等的茶。你要喝一杯再走嗎？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PERSON_EXTRA_POLICE_MINWOO","text":{"KOREA":"아, 괜찮습니다. 곧 퇴근시간이라서요.","JPN":"あ、大丈夫です。もうすぐ退勤時間なので。","ENG":"Oh, thank you, but I’m afraid not. It’s almost time for me to get off work.","TWN":"啊，沒關係。我快到下班時間了。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그렇군요. 제 동생을 도와주신 분인데 이렇게 보내게 되다니, 아쉽네요.","JPN":"そうですか。私の妹を助けてくださった方なのにすぐさまお帰りになるとは、残念です。","ENG":"I see. You’re my sister’s savior, but it’s a shame I can’t do more for you.","TWN":"這樣啊。太可惜了，還沒好好感謝你呢。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아무쪼록 조심해서 들어가시길.","JPN":"くれぐれもお気をつけて。","ENG":"Anyway, thank you and take care.","TWN":"那你慢走。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"네놈의 처세술이란 건 알다가도 모르겠군.","JPN":"貴様の世渡りなぞ、理解ができん。","ENG":"Sometimes, I don’t understand you, Doma.","TWN":"真搞不懂你的處世之道。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"인간들 몰래 녀석을 기절시킨 것도 그렇고…","JPN":"人間には内緒にやつを気絶させたこともそうじゃが……","ENG":"You knocked her out without anyone seeing you do it...","TWN":"偷偷把那傢伙弄暈也是…"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"제 발로 찾아온 목격자를 뭐 하러 살려 보내기까지 한 거냐?","JPN":"自分の足でやってきた目撃者を生きて帰らす必要があるのか？","ENG":"And now, you’re letting a witness go?","TWN":"自己送上門的目擊者，為什麼還要放他走？"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"신중한 경찰은 동료에게 자신의 마지막 행적을 일러두는 법입니다.","JPN":"慎重な警察は仲間に自分の最後の足跡を教えるものです。","ENG":"Police officers usually tell their partners where they’re headed beforehand.","TWN":"謹慎的警察一般都會告訴同事自己的最後行蹤。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"입막음을 위해 성급한 수를 썼다간, 꼬리에 꼬리를 물리는 수가 있어서요.","JPN":"口止めのために浅い手を使ってしまうと、かえって事態が複雑になる可能性もありますので。","ENG":"If I tried covering my tracks now, the consequences will be much greater later on.","TWN":"為了封口而採取的措施，可能會引發連鎖反應。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"게다가……","JPN":"それに……","ENG":"Besides...","TWN":"而且…"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저 친구라면 내버려둬도 괜찮을 겁니다. 쓸만한 정보통이 될 것 같아서 말이죠.","JPN":"あの人なら放っておいても大丈夫でしょう。使えそうな情報通になりそうですから。","ENG":"Keeping him alive would be beneficial as we can use him to grab intel.","TWN":"那個傢伙的話，放任不管也沒關係。感覺他會成為一個不錯的情報網。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"그나저나, 그 녀석이 너에게 제압 당하다니 별일이군.","JPN":"それより、こいつが其方に制圧されるとは珍しいことだな。","ENG":"On another note, I'm surprised at how easily you overpowered her.","TWN":"話說回來，那傢伙竟然被你制服了，真是稀奇啊。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"아무리 방심했다곤 해도, 예전엔 그럭저럭 호각으로 싸웠던 걸로 기억하는데 말이지.","JPN":"いくら油断したと言え、昔はそれなりに対等に戦っていた覚えがあるのじゃが。","ENG":"Even if she was careless, I recall you two being neck and neck.","TWN":"雖然她有些大意，但我記得以前你們還能勉強打個平手呢。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"저로선 안타까운 얘기지만, 주인님의 말씀이 옳습니다.","JPN":"私としては真に残念なことですが、ご主人様のおっしゃる通りです。","ENG":"I’m ashamed to admit it... But you’re right, Mistress.","TWN":"雖然對我來說是個遺憾的事實，但主人的話是對的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"유마의 몸 속에는 지금 인간의 것과 늑대인간, 그리고 흡혈귀의 피가 함께 흐르고 있지요.","JPN":"ユマの体の中には今人間のものとライカンスロープ、そして吸血鬼の血がともに流れています。","ENG":"Right now, Yuma has the blood of human, lycanthrope, and vampire running through her veins.","TWN":"游馬的體內現在流著人類、狼人和吸血鬼的血液。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"세 가지의 피가 섞여 동시에 반발하고 있는데, 타고난 폭력성까지 억누르고 있으니 몸이 허약해지는 건 당연합니다.","JPN":"3つの血が混ざり同時に反発しているのですが、生まれつきの暴力性まで抑えているので体が弱くなるのは当然のことです。","ENG":"All three revolt within her at the same time, and she even suppresses her violent nature. As a result, it's only natural that she's become weaker than before.","TWN":"三種血液交融，不僅會引發排斥反應，還要壓抑與生俱來的暴力傾向，身體虛弱是必然的。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"흐음…","JPN":"ふむ……","ENG":"Hmm...","TWN":"嗯…"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"가끔은 마음껏 날뛸 수 있게 목줄을 풀어주는 것도 괜찮겠지.","JPN":"たまには思いっきり暴れるように口輪を外してやるのもいいだろう。","ENG":"Then I guess letting her off her leash once in a while would be good for her.","TWN":"偶爾放開點束縛，讓她放鬆放鬆吧。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"조만간 녀석에게 마음껏 날뛸 수 있는 무대를 마련해주어라.","JPN":"そのうちやつに存分暴れることのできる舞台を用意してやれ。","ENG":"I suggest you find a suitable place for her to let it all out.","TWN":"之後給那傢伙準備一個可以盡情撒野的舞台吧。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ROSARIA_FALLEN_NULL_NULL","text":{"KOREA":"내게도 마침 여흥거리가 필요하던 참이니 말이다.","JPN":"妾にもちょうど余興が必要だったところだからのう。","ENG":"Plus, it’ll be entertaining for me to watch.","TWN":"正好我也需要一些消遣。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROSARIA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"아, 좋은 생각이십니다.","JPN":"あ、素晴らしいお考えです。","ENG":"Splendid idea, Mistress.","TWN":"主人說的是。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOMA_FALLEN_NULL_NULL","text":{"KOREA":"그럼 제가 괜찮은 무대를 마련해보도록 하죠.","JPN":"では、私が適当な舞台をご用意いたしましょう。","ENG":"Then I shall prepare something as soon as I can.","TWN":"那就讓我來為主人準備一個不錯的舞台吧。"},"stage":{"bg":"CAFE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};